{
  "pattern": "Fold `call @llvm.fabs.* (fadd %x, C)` to `call @llvm.fabs.* (%x)` when C is a constant zero (positive or negative) for floating-point types. Handles scalar and vector types (fixed-width and scalable), commutative fadd (i.e., `fadd(C, %x)`), and preserves fast-math flags and attributes (e.g., noundef) from the original fabs. The transformation eliminates the redundant fadd instruction.",
  "testcases": [
    {
      "name": "scalar_float_fadd_poszero",
      "ir": "; ModuleID = 'test'
source_filename = "test"

declare float @llvm.fabs.f32(float)

define float @test(float %x) {
  %y = fadd float %x, 0.000000e+00
  %z = call float @llvm.fabs.f32(float %y)
  ret float %z
}",
      "expected_optimized_ir": "; ModuleID = 'test'
source_filename = "test"

declare float @llvm.fabs.f32(float)

define float @test(float %x) {
  %z = call float @llvm.fabs.f32(float %x)
  ret float %z
}"
